inline const MyoSuiteTaskDef& GetMyoSuiteTask(std::string_view id) {
  for (const auto& task : kMyoSuiteTasks) {
    if (task.id == id || task.envpool_id == id) {
      return task;
    }
  }
  throw std::runtime_error("Unknown MyoSuite task: " + std::string(id));
}

